-- calc_orders_total_quantity
-- Field: Orders.TotalQuantity
-- Type: aggregation | DataType: integer | Returns: INTEGER

CREATE OR REPLACE FUNCTION calc_orders_total_quantity(p_order_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COALESCE(SUM((quantity)::numeric), 0) FROM order_line_items WHERE "order" = p_order_id))::integer;
$$ LANGUAGE sql STABLE;

-- calc_orders_sub_total
-- Field: Orders.SubTotal
-- Type: aggregation | DataType: number | Returns: NUMERIC

CREATE OR REPLACE FUNCTION calc_orders_sub_total(p_order_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((SELECT COALESCE(SUM((calc_order_line_items_sub_total(order_line_item_id))::numeric), 0) FROM order_line_items WHERE "order" = p_order_id))::numeric;
$$ LANGUAGE sql STABLE;

-- calc_orders_tax_amount
-- Field: Orders.TaxAmount
-- Type: calculated | DataType: number | Returns: NUMERIC

CREATE OR REPLACE FUNCTION calc_orders_tax_amount(p_order_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((COALESCE(CASE WHEN (calc_orders_sub_total(p_order_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_orders_sub_total(p_order_id))::numeric ELSE NULL END, 0) * COALESCE(CASE WHEN ((SELECT tax_rate FROM orders WHERE order_id = p_order_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT tax_rate FROM orders WHERE order_id = p_order_id))::numeric ELSE NULL END, 0)))::numeric;
$$ LANGUAGE sql STABLE;

-- calc_orders_order_total
-- Field: Orders.OrderTotal
-- Type: calculated | DataType: number | Returns: NUMERIC

CREATE OR REPLACE FUNCTION calc_orders_order_total(p_order_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((COALESCE(CASE WHEN (calc_orders_sub_total(p_order_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_orders_sub_total(p_order_id))::numeric ELSE NULL END, 0) + COALESCE(CASE WHEN (calc_orders_tax_amount(p_order_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_orders_tax_amount(p_order_id))::numeric ELSE NULL END, 0)))::numeric;
$$ LANGUAGE sql STABLE;

-- calc_orders_total_paid
-- Field: Orders.TotalPaid
-- Type: aggregation | DataType: number | Returns: NUMERIC

CREATE OR REPLACE FUNCTION calc_orders_total_paid(p_order_id TEXT)
RETURNS NUMERIC AS $$
