$$ LANGUAGE sql STABLE;

-- calc_orders_amount_due
-- Field: Orders.AmountDue
-- Type: calculated | DataType: number | Returns: NUMERIC

CREATE OR REPLACE FUNCTION calc_orders_amount_due(p_order_id TEXT)
RETURNS NUMERIC AS $$
  SELECT (ROUND(((COALESCE(CASE WHEN (calc_orders_order_total(p_order_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_orders_order_total(p_order_id))::numeric ELSE NULL END, 0) - COALESCE(CASE WHEN (calc_orders_total_paid(p_order_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_orders_total_paid(p_order_id))::numeric ELSE NULL END, 0)))::NUMERIC, (2)::INTEGER))::numeric;
$$ LANGUAGE sql STABLE;

-- calc_orders_is_paid_in_full
-- Field: Orders.IsPaidInFull
-- Type: calculated | DataType: boolean | Returns: BOOLEAN

CREATE OR REPLACE FUNCTION calc_orders_is_paid_in_full(p_order_id TEXT)
RETURNS BOOLEAN AS $$
