-- calc_order_line_items_pre_discount
-- Field: OrderLineItems.PreDiscount
-- Type: calculated | DataType: number | Returns: NUMERIC

CREATE OR REPLACE FUNCTION calc_order_line_items_pre_discount(p_order_line_item_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((COALESCE(CASE WHEN ((SELECT quantity FROM order_line_items WHERE order_line_item_id = p_order_line_item_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT quantity FROM order_line_items WHERE order_line_item_id = p_order_line_item_id))::numeric ELSE NULL END, 0) * COALESCE(CASE WHEN ((SELECT unit_price FROM order_line_items WHERE order_line_item_id = p_order_line_item_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT unit_price FROM order_line_items WHERE order_line_item_id = p_order_line_item_id))::numeric ELSE NULL END, 0)))::numeric;
$$ LANGUAGE sql STABLE;

