-- Type: calculated | DataType: number | Returns: NUMERIC

CREATE OR REPLACE FUNCTION calc_order_line_items_discount_amount(p_order_line_item_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((COALESCE(CASE WHEN (calc_order_line_items_pre_discount(p_order_line_item_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_order_line_items_pre_discount(p_order_line_item_id))::numeric ELSE NULL END, 0) * COALESCE(CASE WHEN ((SELECT discount_percent FROM order_line_items WHERE order_line_item_id = p_order_line_item_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT discount_percent FROM order_line_items WHERE order_line_item_id = p_order_line_item_id))::numeric ELSE NULL END, 0)))::numeric;
$$ LANGUAGE sql STABLE;

