CREATE OR REPLACE FUNCTION calc_order_line_items_sub_total(p_order_line_item_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((COALESCE(CASE WHEN (calc_order_line_items_pre_discount(p_order_line_item_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_order_line_items_pre_discount(p_order_line_item_id))::numeric ELSE NULL END, 0) - COALESCE(CASE WHEN (calc_order_line_items_discount_amount(p_order_line_item_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_order_line_items_discount_amount(p_order_line_item_id))::numeric ELSE NULL END, 0)))::numeric;
$$ LANGUAGE sql STABLE;

-- calc_payments_order_date
-- Field: Payments.OrderDate
-- Type: lookup | DataType: datetime | Returns: TIMESTAMPTZ
-- Lookup: OrderDate from related Orders

CREATE OR REPLACE FUNCTION calc_payments_order_date(p_payment_id TEXT)
RETURNS TIMESTAMPTZ AS $$
  SELECT (SELECT order_date::timestamptz FROM orders WHERE order_id = (SELECT "order" FROM payments WHERE payment_id = p_payment_id));
$$ LANGUAGE sql STABLE;

