-- calc_payments_name
-- Field: Payments.Name
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_payments_name(p_payment_id TEXT)
RETURNS TEXT AS $$
  SELECT (LOWER(REPLACE(CONCAT((SELECT NULLIF("order", '') FROM payments WHERE payment_id = p_payment_id), '-pmt-', (SELECT NULLIF(payment_number, '') FROM payments WHERE payment_id = p_payment_id)), ' ', '-')))::text;
$$ LANGUAGE sql STABLE;

-- calc_payments_is_completed
-- Field: Payments.IsCompleted
-- Type: calculated | DataType: boolean | Returns: BOOLEAN

CREATE OR REPLACE FUNCTION calc_payments_is_completed(p_payment_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (CASE WHEN (SELECT NULLIF(payment_status, '') FROM payments WHERE payment_id = p_payment_id) = 'Completed' THEN TRUE ELSE FALSE END)::boolean;
$$ LANGUAGE sql STABLE;

-- calc_payments_completed_amount
-- Field: Payments.CompletedAmount
-- Type: calculated | DataType: number | Returns: NUMERIC

CREATE OR REPLACE FUNCTION calc_payments_completed_amount(p_payment_id TEXT)
RETURNS NUMERIC AS $$
  SELECT (CASE WHEN (SELECT NULLIF(payment_status, '') FROM payments WHERE payment_id = p_payment_id) = 'Completed' THEN ((SELECT amount FROM payments WHERE payment_id = p_payment_id))::text ELSE (0)::text END)::numeric;
$$ LANGUAGE sql STABLE;

-- ============================================================================
-- MANY-SIDE RELATIONSHIP FUNCTIONS
-- These functions aggregate child records for many-side relationships
-- ============================================================================

-- calc_customers_orders
-- Field: Customers.Orders
-- Type: Many-side relationship (backref) to Orders
-- Aggregates: Orders.OrderId where Customer = parent

CREATE OR REPLACE FUNCTION calc_customers_orders(p_customer_id TEXT)
RETURNS TEXT AS $$
  SELECT (
    SELECT STRING_AGG(order_id::TEXT, ', ' ORDER BY order_id)
    FROM orders
    WHERE customer = p_customer_id
  );
$$ LANGUAGE sql STABLE;

-- calc_products_order_line_items
-- Field: Products.OrderLineItems
-- Type: Many-side relationship (backref) to OrderLineItems
-- Aggregates: OrderLineItems.OrderLineItemId where Product = parent

CREATE OR REPLACE FUNCTION calc_products_order_line_items(p_product_id TEXT)
RETURNS TEXT AS $$
  SELECT (
    SELECT STRING_AGG(order_line_item_id::TEXT, ', ' ORDER BY order_line_item_id)
    FROM order_line_items
    WHERE product = p_product_id
  );
$$ LANGUAGE sql STABLE;

-- calc_orders_order_line_items
-- Field: Orders.OrderLineItems
-- Type: Many-side relationship (backref) to OrderLineItems
-- Aggregates: OrderLineItems.OrderLineItemId where Order = parent

CREATE OR REPLACE FUNCTION calc_orders_order_line_items(p_order_id TEXT)
RETURNS TEXT AS $$
  SELECT (
    SELECT STRING_AGG(order_line_item_id::TEXT, ', ' ORDER BY order_line_item_id)
    FROM order_line_items
    WHERE "order" = p_order_id
  );
$$ LANGUAGE sql STABLE;

-- calc_orders_payments
-- Field: Orders.Payments
-- Type: Many-side relationship (backref) to Payments
-- Aggregates: Payments.PaymentId where Order = parent

CREATE OR REPLACE FUNCTION calc_orders_payments(p_order_id TEXT)
RETURNS TEXT AS $$
  SELECT (
    SELECT STRING_AGG(payment_id::TEXT, ', ' ORDER BY payment_id)
    FROM payments
    WHERE "order" = p_order_id
  );
$$ LANGUAGE sql STABLE;

